package com.chaobo.scm.supplier.interfaces.web;

import com.chaobo.scm.common.api.*;import com.chaobo.scm.supplier.application.quality.SupplierQualityEvidenceApplicationService;import com.chaobo.scm.supplier.infrastructure.security.CommandContextFactory;import jakarta.servlet.http.*;import jakarta.validation.*;import jakarta.validation.constraints.*;import org.springframework.security.core.Authentication;import org.springframework.security.core.annotation.AuthenticationPrincipal;import org.springframework.security.oauth2.jwt.Jwt;import org.springframework.web.bind.annotation.*;import java.util.*;
@RestController @RequestMapping("/api/supplier/v1/quality-issues/{issueId}/evidence")public class SupplierQualityEvidenceController {private final SupplierQualityEvidenceApplicationService service;private final CommandContextFactory contexts;public SupplierQualityEvidenceController(SupplierQualityEvidenceApplicationService service,CommandContextFactory contexts){this.service=service;this.contexts=contexts;}@PostMapping public ApiResponse<Long> append(@PathVariable long issueId,@Valid @RequestBody Add b,HttpServletRequest r,Authentication a){return ApiResponse.success(service.append(issueId,b.type(),b.attachmentUrl(),b.content(),contexts.create(r,a)),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}@GetMapping public ApiResponse<List<SupplierQualityEvidenceApplicationService.View>> list(@PathVariable long issueId,@AuthenticationPrincipal Jwt jwt,HttpServletRequest r){return ApiResponse.success(service.list(issueId,scope(jwt)),r.getHeader("X-Request-Id"),r.getHeader("X-Trace-Id"));}private Long scope(Jwt jwt){Number n=jwt.hasClaim("supplier_id")?jwt.getClaim("supplier_id"):null;return n==null?null:n.longValue();}public record Add(@Pattern(regexp="INSPECTION|MEDIA|RECTIFICATION|VERIFICATION|LIABILITY")String type,String attachmentUrl,String content){}}
